  1→import React, { useCallback, useEffect, useRef, useState } from 'react';
  2→import { addons } from 'storybook/internal/manager-api';
  3→import { useStorybookState } from 'storybook/internal/manager-api';
  4→import { useTheme } from 'storybook/internal/theming';
  5→import { EVENTS } from './constants';
  6→import { useIndexedDB } from './useIndexedDB';
  7→import { CodeMirrorEditor, type CodeMirrorEditorHandle } from './CodeMirrorEditor';
  8→import JSON5 from 'json5';
  9→
 10→function idbKeyFor(storyId: string) {
 11→  return `sdui-json-${storyId}`;
 12→}
 13→
 14→function getChannel() {
 15→  try { return addons.getChannel(); } catch { return null; }
 16→}
 17→
 18→function tryParse(text: string): { parsed: any; error: string | null } {
 19→  try {
 20→    return { parsed: JSON.parse(text), error: null };
 21→  } catch {
 22→    try {
 23→      return { parsed: JSON5.parse(text), error: null };
 24→    } catch (e) {
 25→      return { parsed: null, error: (e as Error).message };
 26→    }
 27→  }
 28→}
 29→
 30→export function JsonEditorPanel() {
 31→  const state = useStorybookState();
 32→  const storyId = state.storyId ?? '';
 33→  const theme = useTheme();
 34→  const storedThemePref = typeof localStorage !== 'undefined'
 35→    ? localStorage.getItem('sb-ui-theme')
 36→    : null;
 37→  const isDarkMode = theme.base === 'dark' || storedThemePref === 'dark';
 38→
 39→  const [defaultJson, setDefaultJson] = useState<string>('');
 40→  const [text, setText] = useState<string>('');
 41→  const [error, setError] = useState<string | null>(null);
 42→  const [dirty, setDirty] = useState(false);
 43→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 44→  const editorRef = useRef<CodeMirrorEditorHandle>(null);
 45→  const retryRef = useRef<ReturnType<typeof setInterval> | null>(null);
 46→  const initializedRef = useRef(false);
 47→
 48→  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));
 49→
 50→  useEffect(() => {
 51→    return () => {
 52→      if (debounceRef.current) clearTimeout(debounceRef.current);
 53→      if (retryRef.current) clearInterval(retryRef.current);
 54→    };
 55→  }, []);
 56→
 57→  useEffect(() => {
 58→    if (debounceRef.current) {
 59→      clearTimeout(debounceRef.current);
 60→      debounceRef.current = null;
 61→    }
 62→    setDefaultJson('');
 63→    setText('');
 64→    setDirty(false);
 65→    setError(null);
 66→    initializedRef.current = false;
 67→  }, [storyId]);
 68→
 69→  useEffect(() => {
 70→    const channel = getChannel();
 71→    if (!channel) return;
 72→
 73→    const onSetDefault = (json: string) => {
 74→      setDefaultJson(json);
 75→      if (retryRef.current) {
 76→        clearInterval(retryRef.current);
 77→        retryRef.current = null;
 78→      }
 79→    };
 80→
 81→    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 82→    channel.emit(EVENTS.REQUEST_DEFAULT);
 83→
 84→    let retryCount = 0;
 85→    retryRef.current = setInterval(() => {
 86→      retryCount++;
 87→      if (retryCount > 20) {
 88→        if (retryRef.current) clearInterval(retryRef.current);
 89→        return;
 90→      }
 91→      channel.emit(EVENTS.REQUEST_DEFAULT);
 92→    }, 250);
 93→
 94→    return () => {
 95→      channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 96→      if (retryRef.current) {
 97→        clearInterval(retryRef.current);
 98→        retryRef.current = null;
 99→      }
100→    };
101→  }, [storyId]);
102→
103→  useEffect(() => {
104→    if (!ready || !defaultJson) return;
105→    if (initializedRef.current) return;
106→    initializedRef.current = true;
107→    const initial = stored ?? defaultJson;
108→    setText(initial);
109→    editorRef.current?.setValue(initial);
110→    setDirty(!!stored);
111→    setError(null);
112→    // eslint-disable-next-line react-hooks/exhaustive-deps
113→  }, [ready, defaultJson, storyId]);
114→
115→  const handleChange = useCallback(
116→    (value: string) => {
117→      setText(value);
118→
119→      if (debounceRef.current) clearTimeout(debounceRef.current);
120→
121→      debounceRef.current = setTimeout(() => {
122→        const { parsed, error: parseErr } = tryParse(value);
123→        if (parsed !== null) {
124→          save(value);
125→          setDirty(true);
126→          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
127→        } else {
128→          save(value);
129→          setDirty(true);
130→        }
131→      }, 400);
132→    },
133→    [save],
134→  );
135→
136→  const handleValidationChange = useCallback(
137→    (hasErrors: boolean, message: string | null) => {
138→      setError(hasErrors ? message : null);
139→    },
140→    [],
141→  );
142→
143→  const handleReset = useCallback(() => {
144→    remove();
145→    setText(defaultJson);
146→    editorRef.current?.setValue(defaultJson);
147→    setDirty(false);
148→    setError(null);
149→    const { parsed } = tryParse(defaultJson);
150→    if (parsed !== null) {
151→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
152→    }
153→  }, [defaultJson, remove]);
154→
155→  const handleFormat = useCallback(() => {
156→    const currentText = editorRef.current?.getValue() ?? '';
157→    const { parsed, error: parseErr } = tryParse(currentText);
158→    if (parsed !== null) {
159→      const formatted = JSON.stringify(parsed, null, 2);
160→      setText(formatted);
161→      editorRef.current?.setValue(formatted);
162→      save(formatted);
163→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
164→      setError(null);
165→    } else {
166→      setError(parseErr);
167→    }
168→  }, [save]);
169→
170→  const s = isDarkMode ? darkStyles : lightStyles;
171→
172→  if (!storyId) {
173→    return <div style={s.empty}>Select a story to edit its JSON.</div>;
174→  }
175→
176→  const isWaiting = !defaultJson && !text;
177→
178→  return (
179→    <div style={s.container}>
180→      <div style={s.toolbar}>
181→        <span style={s.label}>
182→          SDUI JSON {dirty && <span style={s.badge}>edited</span>}
183→        </span>
184→        <div style={s.actions}>
185→          <button
186→            style={s.btn}
187→            onClick={handleFormat}
188→            title="Format JSON (normalizes to strict JSON)"
189→          >
190→            Format
191→          </button>
192→          <button
193→            style={{ ...s.btn, ...(dirty ? s.btnReset : s.btnDisabled) }}
194→            onClick={handleReset}
195→            disabled={!dirty}
196→            title="Reset to story default"
197→          >
198→            Reset
199→          </button>
200→        </div>
201→      </div>
202→
203→      {error && !isWaiting && <div style={s.error}>{error}</div>}
204→
205→      {isWaiting ? (
206→        <div style={s.empty}>
207→          Waiting for story to send SDUI JSON…
208→          <br />
209→          <span style={{ fontSize: 11, opacity: 0.7 }}>
210→            If this persists, the current story may not use useSDUIJsonEditor().
211→          </span>
212→        </div>
213→      ) : (
214→        <div style={s.editorContainer}>
215→          <CodeMirrorEditor
216→            ref={editorRef}
217→            value={text}
218→            onChange={handleChange}
219→            onValidationChange={handleValidationChange}
220→            isDarkMode={isDarkMode}
221→          />
222→        </div>
223→      )}
224→    </div>
225→  );
226→}
